messages.content:
CLUSTER:
[
 {
  "riskId": "risk.demand-discontinuity.statista-stage-blend-tambase",
  "title": "If Statista's country MW blends pipeline stages, the CE apportionment inside tamBase is counting halls that don't exist yet",
  "narrative": "tamBase's only CE-specific hop is 'CE-7 = 39.8% of Europe colo MW (Statista).' But the corpus shows Statista-style country figures may not be operational-only: summed Statista country colo exceeds CBRE's total European capacity, and the same digest shows how easily vendors blend stages — DC Byte's Amsterdam 'supply' is 1,849 MW while operational capacity is 852 MW, a 2.2x gap. If the Statista series leans toward committed/under-construction capacity, the CE share and the country weights are computed on MW that generate zero PDU revenue in 2026 — and with EMEA construction plateaued at 2.5 GW, much of that phantom base stays phantom through the venture's window. This is a different failure than the ±40% band contemplates: the band prices scope-down uncertainty on the global number, not stage-blending in the one CE-specific multiplier.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "Vendor capacity figures demonstrably blend pipeline stages: DC Byte reports Amsterdam 'Total Supply' of 1,849 MW (live + under construction + committed + early stage) against 852 MW operational (C&W) — the same city, a 2.2x gap purely from stage definition",
    "refs": [
     "digest:geo-NL#c6",
     "digest:geo-NL#c0"
    ]
   },
   {
    "step": "propagation",
    "text": "tamBase multiplies the €775M Europe estimate by 'CE-7 = 39.8% of Europe colo MW' from the Statista series, whose scope ('colocation and scale-colocation IT power') no second vendor replicates; if it includes non-operational MW, the euro-revenue-relevant CE base is smaller — and with EMEA under-construction plateaued at ~2.5 GW, blended-in pipeline MW does not convert to PDU-buying halls inside 12 months",
    "refs": [
     "ledger:tamBase",
     "digest:geo-NL#c3"
    ]
   },
   {
    "step": "model-impact",
    "text": "The 2025/26 revenue-relevant tamBase sits below the curated €320M for a reason orthogonal to the global-number spread the sensitivity band was built from; every downstream node inherits the overstatement proportionally",
    "refs": [
     "ledger:tamBase",
     "digest:tam-global-crosscheck#c0"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Per-country operational vs pipeline MW splits for CE-7",
    "where": "Cushman & Wakefield EMEA Data Centre Update (semi-annual, country tables)",
    "threshold": "Statista country figure exceeding C&W operational figure by >20% for DE or NL",
    "updates": "increases"
   },
   {
    "signal": "DC Byte live vs total-supply ratios for Frankfurt, Amsterdam, Warsaw",
    "where": "DC Byte market pages / quarterly market summaries",
    "threshold": "Live share of total supply <55% in the CE hubs",
    "updates": "increases"
   }
  ],
  "judgeTotal": 15
 },
 {
  "riskId": "risk.definition-scopedown.intelligent-subset-inflation",
  "title": "The TAM counts basic and metered PDUs the venture doesn't sell — and Germany's intelligent slice is growing at half the assumed rate",
  "narrative": "The venture sells intelligent rack PDUs; tamBase is scoped as the rack-PDU market, all classes — basic, metered, switched, intelligent. The definitional gap is treated as harmless because 'intelligent is the growth segment'. But the corpus says the intelligent subset is materially smaller than the headline ($2.1B of $2.81B globally at best, with publisher definitions in open contradiction), and — critically — Germany, which carries 50% of the geographic weight, shows intelligent-PDU growth of only 5.2–5.3% CAGR, versus the 9% assumed for the market. Add 60–70% import dependence in Eastern Europe served at low price points, and the CE-relevant intelligent base could be 60–70% of the headline €320M. The venture is sizing the market for a product category it only partially competes in.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "Product scope (intelligent PDUs) is narrower than the tamBase scope (all rack PDUs): global intelligent-PDU market is sized at $2.1B (2024) against the $2.81B all-class rack-PDU base — roughly a 25–30% haircut before any regional adjustment",
    "refs": [
     "profile:Product",
     "digest:tam-global-crosscheck#c11",
     "digest:tam-global-crosscheck#c0"
    ]
   },
   {
    "step": "propagation",
    "text": "CE demand skews toward the non-intelligent end: Germany's intelligent-PDU segment grows at only 5.2–5.3% CAGR (half the market rate), and Eastern Europe runs 60–70% import dependence consistent with price-led basic/metered purchasing — so the intelligent share of CE spend is lower than the global mix, not higher",
    "refs": [
     "digest:tam-global-crosscheck#c13",
     "digest:tam-global-crosscheck#c14",
     "digest:tam-base#c15"
    ]
   },
   {
    "step": "model-impact",
    "text": "The venture-relevant base is the CE intelligent slice, plausibly ~70% of the €320M headline — every downstream funnel stage (SAM reach, Year-1 obtainable) is computed against demand the product cannot address",
    "refs": [
     "ledger:tamBase",
     "ledger:serviceableFactor"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "SKU mix (basic/metered vs switched/intelligent) in CE distributor catalogs and price lists",
    "where": "Rittal, Bachmann, and CE master-distributor (e.g., Also/Ingram DC-infrastructure) published price lists",
    "threshold": "Basic+metered SKUs >40% of listed rack-PDU line items in DE/PL catalogs",
    "updates": "increases"
   },
   {
    "signal": "PDU class specified in German and Polish colocation fit-out tenders",
    "where": "Frankfurt colo tender documents; Polish public-sector DC procurement portal (platformazakupowa)",
    "threshold": "≥half of tenders specifying metered-only or basic PDUs",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17
 },
 {
  "riskId": "risk.definition-scopedown.statista-pipeline-mw-inflation",
  "title": "The CE-7 = 39.8% hop is built on Statista MW that don't reconcile with anyone else's Europe — pipeline capacity counted as PDU-buying capacity",
  "narrative": "Every geo ratio and the CE-7-of-Europe multiplier come from one Statista table whose summed 2024 country figures (~7.6GW) exceed CBRE's 4,726MW European colocation supply and even CBRE's 5.8GW total European DC capacity. Something in Statista's 'colocation and scale-colocation IT power' definition counts capacity that is contracted or under construction, not energized — Germany 'growing' 24.8% in a single forecast year while CBRE reports only 937MW of new supply for all of Europe is the tell. PDUs are bought at fit-out, per energized MW. If the padding is concentrated in the growth markets (Germany, Poland) rather than the mature FLAPD stock, the CE-7 share of Europe is overstated on a delivered-capacity basis — and the venture's Year-1 window is sized against halls that won't be racked for two years.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "Statista's summed 2024 per-country colo figures (~7.6GW) exceed CBRE's Q4-2024 European colocation supply (4,726MW) and approach-exceed CBRE's 5.8GW total European DC capacity — an unreconciled >1.6x scope gap in the sole source behind the CE-7 apportionment",
    "refs": [
     "digest:geo-region-denominator#c1",
     "digest:geo-region-denominator#c3",
     "digest:geo-region-denominator#c5"
    ]
   },
   {
    "step": "propagation",
    "text": "The inflation is growth-market-skewed: Statista shows Germany jumping 1,737→2,167 MW (+24.8%) and Poland +27.6% in 2026, while CBRE counts only 937MW of new supply delivered across all of Europe in 2025 — meaning the CE-7 numerator carries proportionally more announced/contracted capacity than the FLAPD-heavy denominator",
    "refs": [
     "digest:geo-region-denominator#c2",
     "digest:geo-region-denominator#c7",
     "ledger:geo.DE"
    ]
   },
   {
    "step": "model-impact",
    "text": "The 39.8% CE-7-of-Europe multiplier in tamBase's derivation is overstated on an energized-MW basis; rack-PDU spend follows fit-out of live halls, so the CE base for the venture's 12-month window is smaller than the ledger's €320M implies",
    "refs": [
     "ledger:tamBase"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Delivered (not announced) MW per CE market versus Statista's year-over-year increments",
    "where": "CBRE quarterly 'Europe Data Centres Figures' (Frankfurt/secondary-market delivery tables)",
    "threshold": "Frankfurt+Berlin deliveries <200MW in 2026 against Statista's implied +430MW for Germany",
    "updates": "increases"
   },
   {
    "signal": "Energization delays cited by CE operators (grid connection queues in Frankfurt, Amsterdam moratorium after-effects)",
    "where": "Operator capex/earnings calls (Vantage, NTT GDC, Data4) and German TSO (TenneT/Amprion) connection-queue disclosures",
    "threshold": "Multiple operators pushing CE energization dates by ≥12 months",
    "updates": "increases"
   }
  ],
  "judgeTotal": 14
 },
 {
  "riskId": "risk.boundary-substitution.psu-shelf-cagr-divergence-erodes-tambase",
  "title": "The model's own cross-check source is measuring the substitution: PDU+PSU spend growing 21% while rack-PDU grows 9% means the PDU share of rack power is falling every year",
  "narrative": "tamBase's high-end cross-check takes BIS/R&M's Europe PDUs+PSUs figure ($2.45B, 2024) and applies a static ~55% PDU share to get the €495M ceiling. But look at the growth rates the ledger itself carries: the combined PDUs+PSUs category is forecast at 21.23% CAGR while rack-PDU-only sources cluster at 9–9.7%. Arithmetic forces the gap into the non-PDU component — PSUs and power shelves, the very substitutes the boundary excludes — which must be growing at roughly 30%+ to reconcile the two series. That divergence is not a data quirk; it is the substitution trend expressed in euros. A static 55% PDU share is wrong in the direction that matters: it decays each year of the venture's window, dragging both the cross-check ceiling and the curated €320M toward the band's low end even if data-center construction booms.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "BIS/R&M forecast the Europe PDUs+PSUs market at 21.23% CAGR ($2.45B→$20.05B by 2035), while rack-PDU-only forecasts cluster at 9.7% (GVR) — a 2.2x growth-rate gap within overlapping scopes",
    "refs": [
     "digest:tam-base#c2",
     "digest:tam-base#c3",
     "digest:tam-base#c0"
    ]
   },
   {
    "step": "propagation",
    "text": "The growth gap is mathematically absorbed by the PSU/power-shelf component of the combined category — the excluded substitutes — meaning the PDU value share of European rack power declines every year; the ledger's cross-check applies a static ~55% PDU share to derive the €495M ceiling",
    "refs": [
     "ledger:tamBase",
     "digest:tam-base#c4"
    ]
   },
   {
    "step": "model-impact",
    "text": "Both the €495M high edge and the curated €320M assume PDU share of rack-power spend holds through the sizing window; if the share is decaying at the rate the two CAGRs imply, the effective 2026-27 PDU-only base sits below the curated value and the 240–520 band is skewed high, not symmetric",
    "refs": [
     "ledger:tamBase",
     "digest:tam-base#c5"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Revenue mix between rack-PDU and PSU/power-shelf product lines at incumbents",
    "where": "Vertiv quarterly earnings (critical power segment detail); Delta Electronics and LiteOn investor materials (OCP power-shelf suppliers)",
    "threshold": "Shelf/PSU lines growing >2x the PDU line for two consecutive quarters",
    "updates": "increases"
   },
   {
    "signal": "Updated rack-PDU-only vs PDU+PSU base-year figures at next report vintages",
    "where": "Grand View Research rack-PDU update (2026 vintage); Research and Markets/BIS Europe PDUs+PSUs update",
    "threshold": "Implied PDU share of the combined category dropping below 50%",
    "updates": "increases"
   }
  ],
  "judgeTotal": 16
 },
 {
  "riskId": "risk.ledger-self-audit.statista-scale-colo-scope-inflation",
  "title": "One vendor's unverified 'colocation and scale-colocation' definition is both the geo split and a hidden multiplier inside tamBase — normalization launders the scope error out of sight",
  "narrative": "Every geo node and the 39.8% CE-of-Europe step inside tamBase come from a single Statista series whose scope no second vendor reproduces. The corpus shows the series runs hot: summed 2024 Statista country colo (~7.6GW) exceeds CBRE's 5.8GW figure for ALL European DC capacity, and PMR's CEE numbers imply a regional base ~5× smaller than the Statista-derived one. Because the seven geo shares are normalized to 1.00, the axis looks self-consistent no matter how wrong the underlying series is — but the same series also sets the absolute CE-of-Europe fraction in tamBase, where a scope inflation does not cancel. If 'scale-colocation' quietly includes hyperscale self-build shells or contracted-not-energized capacity, the CE market is being sized off MW that either doesn't exist yet or buys PDUs through channels outside this model.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "Statista's per-country colocation figures share no verified common scope with any benchmark: the summed 2024 country values (~7.6GW) exceed CBRE's 4,726MW European colo supply and even its 5.8GW total-European-capacity figure, and no second vendor uses the 'colocation and scale-colocation IT power' definition",
    "refs": [
     "digest:geo-region-denominator#c1",
     "digest:geo-region-denominator#c3",
     "digest:geo-region-denominator#c5"
    ]
   },
   {
    "step": "propagation",
    "text": "Independent regional checks confirm the same direction of error: PMR/Atman put Poland at ~200MW commercial and >1/3 of a CEE total ≈600MW, versus the Statista-derived CE-7 base of 3,451MW — meaning the series most plausibly counts capacity classes (self-build shells, contracted pipeline) that do not purchase rack PDUs as modeled",
    "refs": [
     "digest:geo-PL#c13",
     "digest:geo-PL#c14",
     "ledger:geo.PL"
    ]
   },
   {
    "step": "model-impact",
    "text": "The CE-7 = 39.8%-of-Europe step in tamBase's derivation was computed on an inflated numerator and denominator of unknown relative bias; recomputing CE's weight on a CBRE-consistent scope shrinks the CE slice of the European base, cutting tamBase below its curated value independent of the global-base and Europe-share disputes — while the normalized geo shares hide that anything moved",
    "refs": [
     "ledger:tamBase",
     "ledger:geo.DE",
     "digest:geo-region-denominator#c5"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "CBRE Europe Data Centres quarterly country/market supply figures vs Statista's same-year per-country values",
    "where": "CBRE 'Europe Data Centres Figures' quarterly PDF releases (Frankfurt, Amsterdam, Warsaw, Zurich, Vienna market pages)",
    "threshold": "CBRE country supply persistently <60% of Statista's figure for the same country and year",
    "updates": "increases"
   },
   {
    "signal": "Country-level MW tables from the gated EUDCA 'State of European Data Centres 2026' report",
    "where": "EUDCA report release and member briefings",
    "threshold": "EUDCA CE country totals implying CE-7 <30% of Europe on a consistent scope",
    "updates": "increases"
   }
  ],
  "judgeTotal": 18
 },
 {
  "riskId": "risk.definition-scopedown.europe-share-arithmetic-ghost",
  "title": "The 'Europe ≈ 30%' hop is an arithmetic ghost — no source states it, and regional datapoints put Europe closer to 24%",
  "narrative": "The entire €320M chain multiplies GVR's $2.81B global figure by 'Europe ≈ 30%', a number no publisher states — it is inferred by eyeballing the residual after North America's 38%. But the only regional revenue datapoints in the corpus cut the other way: the US alone is $579.7M of a $2.1B global intelligent-PDU market (~28% for one country), APAC is uniformly described as the fastest-growing region, and Germany — half of the CE weight — is forecast to grow its intelligent-PDU segment at only 5.2–5.3%, roughly half the global rate. If PDU revenue is more NA/APAC-skewed than DC capacity, Europe sits at 22–25%, not 30%, and every downstream node inherits the error. This is not 'the band's low end' — it is a specific hop whose value was never observed, drifting in a specific direction.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "The 30% Europe multiplier in tamBase's derivation is unsourced: GVR states only NA = 38%, and no source found anywhere states a Europe rack-PDU revenue share",
    "refs": [
     "ledger:tamBase",
     "digest:tam-global-crosscheck#c1"
    ]
   },
   {
    "step": "propagation",
    "text": "Regional evidence skews the residual away from Europe: US intelligent-PDU market alone is $579.7M of $2.1B global (~28%), China is on a 6.4% CAGR toward $498M, and Germany's intelligent-PDU CAGR (5.2–5.3%) runs at roughly half the 9.7% global rack-PDU rate — meaning Europe's share is both lower than 30% and declining through the venture window",
    "refs": [
     "digest:tam-global-crosscheck#c15",
     "digest:tam-global-crosscheck#c13",
     "digest:tam-global-crosscheck#c14",
     "digest:tam-global-crosscheck#c0"
    ]
   },
   {
    "step": "model-impact",
    "text": "Europe at ~24% instead of 30% rescales the whole scope-down chain multiplicatively — the curated €320M point value sits above the recomputed primary derivation, and SAM/YAM shrink proportionally",
    "refs": [
     "ledger:tamBase"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Regional revenue split in the next Omdia Rack PDU Annual Market Analysis or GVR report edition",
    "where": "Omdia rack-PDU tracker (2025 update) regional tables; Grand View Research report refresh",
    "threshold": "Europe stated at <27% of global rack-PDU revenue",
    "updates": "increases"
   },
   {
    "signal": "EMEA vs Americas revenue mix for rack-power product lines in incumbent segment reporting",
    "where": "Vertiv 10-K segment disclosures; Legrand universe-by-region commentary in annual results",
    "threshold": "EMEA rack-power growth persistently below Americas by >4pp",
    "updates": "increases"
   }
  ],
  "judgeTotal": 16
 },
 {
  "riskId": "risk.definition-scopedown.crosscheck-ceiling-contamination",
  "title": "The €495M cross-check ceiling grows at 21.23% CAGR — it is measuring the substitute architecture, and the band's upside is a mirage",
  "narrative": "The high end of tamBase's band (€520M, worth +€3.3M YAM at the band edge) rests on one calculation: BIS's €2.45B Europe 'PDUs + PSUs' figure × an unsourced ~55% PDU share. But that BIS category grows at 21.23% CAGR — a rate no mature rack-PDU market exhibits (every rack-PDU-only source says 5.4–9.8%). A 21% growth rate in a 'PDUs and PSUs' category is the signature of OCP power shelves and rack-level DC power supplies — precisely the substitute architecture the model's boundary excludes. The ceiling isn't a generous estimate of the venture's market; it's a measurement of the thing eating the venture's market. If the board sizes hiring, inventory, or the raise against the band midpoint on the theory that upside and downside are symmetric, they are capitalizing a number that contains the competitor architecture's growth.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "The BIS/R&M Europe 'PDUs + PSUs' base ($2.45B → $20.05B, 21.23% CAGR) used for the crossCheck ceiling grows 2–4x faster than every rack-PDU-only estimate (5.4–9.8% across five publishers) — a growth signature inconsistent with the rack-PDU scope it is being used to validate",
    "refs": [
     "digest:tam-base#c2",
     "digest:tam-base#c3",
     "digest:tam-global-crosscheck#c7",
     "digest:tam-global-crosscheck#c6"
    ]
   },
   {
    "step": "propagation",
    "text": "The excess growth must sit in the PSU/DC-power-shelf portion of the category — the excluded substitute — and the '~55% PDU share' applied to strip it out is unsourced, so the €495M ceiling inherits an unknown fraction of substitute-architecture revenue; MarketsAndMarkets' 19.5% CAGR for its broader rack+floor PDU scope shows the same contamination pattern",
    "refs": [
     "ledger:tamBase",
     "digest:tam-base#c4",
     "digest:tam-base#c5"
    ]
   },
   {
    "step": "model-impact",
    "text": "tamBase's true uncertainty is asymmetric: the primary chain supports €240–320, while the 520 high edge is scope-contaminated — any planning premised on the band's symmetric upside (the +€200M dTam edge in the affordances) overstates the venture's realistic ceiling",
    "refs": [
     "ledger:tamBase"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Sub-segment split (PDU vs PSU/power shelf) and per-segment CAGRs in the BIS Europe report sample pages or ToC",
    "where": "Research and Markets / giiresearch listing pages for the Europe PDUs+PSUs report; BIS Research sample-request materials",
    "threshold": "PSU/shelf sub-segment shown growing >20% while PDU sub-segment grows <10%",
    "updates": "increases"
   },
   {
    "signal": "Divergence between broad 'data center PDU' category growth and rack-PDU-only growth across publisher updates",
    "where": "MarketsAndMarkets Data Center PDU report refreshes vs Mordor/GVR rack-PDU-only refreshes",
    "threshold": "Broad-scope CAGR remaining ≥2x rack-PDU-only CAGR in 2026 editions",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17
 },
 {
  "riskId": "risk.ledger-self-audit.europe-share-phantom-multiplier",
  "title": "The 'Europe ≈ 30%' step in the TAM chain is a number nobody published — the whole funnel hangs on an invented multiplier",
  "narrative": "tamBase is derived as Global $2.81B × Europe ≈ 30% × CE 39.8%. The middle factor is the load-bearing one, and the cited GVR source states only North America's 38% share — no source in the corpus states Europe's rack-PDU share at all. With NA at 38% and APAC absorbing the fastest hyperscale buildout, Europe's true share of a rack-PDU market whose growth is capacity-led could plausibly sit at 20–25%. A hostile diligence partner strikes the 30% first because it is the only unattributed factor in an otherwise sourced expression, and every downstream node — SAM, YAM, every geo and segment slice — scales linearly with it.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "The derivation's 'Europe ≈ 30% [est.]' factor is flagged in the corpus as unsourced: GVR publishes only NA = 38%, and no retrieved source states a Europe rack-PDU share",
    "refs": [
     "digest:tam-global-crosscheck#c1",
     "digest:tam-base#c1",
     "ledger:tamBase"
    ]
   },
   {
    "step": "propagation",
    "text": "Global publisher estimates for the base itself already span >2x ($1.7B–$3.94B), so an invented regional split compounds on an unstable base; if Europe is 22–25% (consistent with capacity-led demand concentrating in NA/APAC AI builds), the €775M Europe base falls to €570–650M before the CE step is applied",
    "refs": [
     "digest:tam-global-crosscheck#c0",
     "digest:tam-global-crosscheck#c4",
     "ledger:tamBase"
    ]
   },
   {
    "step": "model-impact",
    "text": "tamBase re-derives to roughly €230–260M — below the curated €320M and near the band's low edge for a structural reason the band does not encode (the band was framed as source dispersion, not as a phantom multiplier); SAM and YAM scale down proportionally",
    "refs": [
     "ledger:tamBase",
     "ledger:serviceableFactor",
     "ledger:obtainableFactor"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "EMEA share of rack-power / critical-infrastructure segment revenue disclosed by Vertiv and Schneider",
    "where": "Vertiv 10-K segment disclosures and Schneider Electric annual report, Energy Management segment regional split",
    "threshold": "EMEA consistently <25% of relevant segment revenue",
    "updates": "increases"
   },
   {
    "signal": "Headline EU rack-PDU market size once the directly-scoped report is opened",
    "where": "IndexBox 'Rack PDUs Market in the European Union' report (currently paywalled, named in the ledger's promotion path)",
    "threshold": "EU figure implying Europe <27% of the GVR global base",
    "updates": "increases"
   }
  ],
  "judgeTotal": 14
 }
]

Every riskId must appear in exactly one group (as keepId or inside absorbs).
Emit JSON: { rationale, groups: [{keepId, absorbs: [true-duplicate riskIds, [] if none], foldedIndicators: []}] }
